63	void ALFPWorldMapPawn::UpdateMoveAnimation(float Alpha)
64	{
65		FVector NewLocation = FMath::Lerp(MoveStartLocation, MoveTargetLocation, Alpha);
66		SetActorLocation(NewLocation);
