58	void ALFPWorldMapPlayerController::Tick(float DeltaTime)
59	{
60		Super::Tick(DeltaTime);
61	
62		if (bIsDragging)
63		{
64			DragTime += DeltaTime;
65		}
66	
67		// 更新相机位置和旋转
68		// 相机位置：CameraOffset（XY 平移）+ CurrentZoom（高度）
69		FVector TargetLocation = CameraOffset + FVector(0.f, 0.f, CurrentZoom);
70	
71		// 相机旋转：俯视角
72		FRotator TargetRotation(CameraPitchAngle, 0.f, 0.f);
73	
74		// 平滑插值并设置
75		FRotator CurrentRotation = GetControlRotation();
76		if (bSnapCameraNextFrame)
77		{
78			SetControlRotation(TargetRotation);
79		}
80		else
81		{
82			SetControlRotation(FMath::RInterpTo(CurrentRotation, TargetRotation, DeltaTime, 5.0f));
83		}
84	
85		// 通过 Pawn 控制相机位置（如果有 Pawn）
86		if (APawn* ControlledPawn = GetPawn())
87		{
88			if (bSnapCameraNextFrame)
89			{
90				// 首帧直接跳到目标位置，避免切场景后相机大幅滑动
91				ControlledPawn->SetActorLocation(TargetLocation);
92				bSnapCameraNextFrame = false;
93			}
94			else
95			{
96				FVector CurrentLocation = ControlledPawn->GetActorLocation();
97				ControlledPawn->SetActorLocation(
98					FMath::VInterpTo(CurrentLocation, TargetLocation, DeltaTime, 5.0f)
99				);
100			}
101		}
102	}
