128	void ALFPWorldMapPlayerController::OnConfirmAction(const FInputActionValue& Value)
129	{
130		bIsDragging = false;
131		if (DragTime > DragThresholdTime)
132		{
133			DragTime = 0.f;
134			return;
135		}
136		DragTime = 0.f;
137	
138		// 编辑器模式优先处理
139		if (WorldMapEditorComponent && WorldMapEditorComponent->IsEditorActive())
140		{
141			// 射线检测点击的节点
142			FHitResult HitResult;
143			GetHitResultUnderCursor(ECC_Visibility, false, HitResult);
144			ALFPWorldMapNode* ClickedNode = Cast<ALFPWorldMapNode>(HitResult.GetActor());
145	
146			ELFPWorldMapEditorTool CurrentTool = WorldMapEditorComponent->GetCurrentTool();
147	
148			switch (CurrentTool)
149			{
150			case ELFPWorldMapEditorTool::WMET_PlaceNode:
151				{
152					// 射线投射到 Z=0 平面获取世界坐标
153					FVector WorldOrigin, WorldDirection;
154					DeprojectMousePositionToWorld(WorldOrigin, WorldDirection);
155					if (FMath::Abs(WorldDirection.Z) > KINDA_SMALL_NUMBER)
156					{
157						float T = -WorldOrigin.Z / WorldDirection.Z;
158						FVector HitPoint = WorldOrigin + WorldDirection * T;
159						WorldMapEditorComponent->PlaceNodeAt(FVector2D(HitPoint.X, HitPoint.Y));
160					}
161				}
162				break;
163	
164			case ELFPWorldMapEditorTool::WMET_RemoveNode:
165				if (ClickedNode)
166				{
167					WorldMapEditorComponent->SelectNode(ClickedNode);
168					WorldMapEditorComponent->RemoveSelectedNode();
169				}
170				break;
171	
172			case ELFPWorldMapEditorTool::WMET_MoveNode:
173				if (ClickedNode)
174				{
175					WorldMapEditorComponent->SelectNode(ClickedNode);
176				}
177				else if (WorldMapEditorComponent->GetSelectedNode())
178				{
179					// 移动到点击位置
180					FVector WorldOrigin, WorldDirection;
181					DeprojectMousePositionToWorld(WorldOrigin, WorldDirection);
182					if (FMath::Abs(WorldDirection.Z) > KINDA_SMALL_NUMBER)
183					{
184						float T = -WorldOrigin.Z / WorldDirection.Z;
185						FVector HitPoint = WorldOrigin + WorldDirection * T;
186						WorldMapEditorComponent->MoveSelectedNodeTo(FVector2D(HitPoint.X, HitPoint.Y));
187					}
188				}
189				break;
190	
191			case ELFPWorldMapEditorTool::WMET_ConnectEdge:
192				if (ClickedNode)
193				{
194					WorldMapEditorComponent->HandleEdgeConnection(ClickedNode);
195				}
196				break;
197	
198			case ELFPWorldMapEditorTool::WMET_RemoveEdge:
199				if (ClickedNode)
200				{
201					WorldMapEditorComponent->HandleEdgeRemoval(ClickedNode);
202				}
203				break;
204	
205			case ELFPWorldMapEditorTool::WMET_SetNodeParams:
206				if (ClickedNode)
207				{
208					WorldMapEditorComponent->SelectNode(ClickedNode);
209					WorldMapEditorComponent->ApplyParamsToSelectedNode();
210				}
211				break;
212	
213			default:
214				break;
215			}
216			return;
217		}
218	
219		// 游戏模式：棋子移动中屏蔽点击
220		ALFPWorldMapManager* Manager = GetWorldMapManager();
221		if (Manager && Manager->IsPawnMoving()) return;
222	
223		// 游戏模式：点击节点移动或进入
224		FHitResult HitResult;
225		GetHitResultUnderCursor(ECC_Visibility, false, HitResult);
226		ALFPWorldMapNode* ClickedNode = Cast<ALFPWorldMapNode>(HitResult.GetActor());
227	
228		if (ClickedNode)
229		{
230			if (!Manager || !Manager->GetPlayerState()) return;
231	
232			int32 CurrentNodeID = Manager->GetPlayerState()->CurrentNodeID;
233	
234			// 点击当前节点 → 进入节点
235			if (ClickedNode->NodeID == CurrentNodeID)
236			{
237				EnterNode(ClickedNode);
238				return;
239			}
240	
241			// 点击相邻可达节点 → 移动
242			TArray<int32> ReachableIDs = Manager->GetPlayerState()->GetReachableNodeIDs(Manager);
243			if (ReachableIDs.Contains(ClickedNode->NodeID))
244			{
245				MoveToNode(ClickedNode);
246			}
247			else
248			{
249				// 不可达，只选中
250				SelectNode(ClickedNode);
251			}
252		}
253	}
