210	bool ALFPWorldMapManager::RemoveEdge(int32 FromID, int32 ToID)
211	{
212		FIntPoint Key = MakeEdgeKey(FromID, ToID);
213	
214		ALFPWorldMapEdge** Found = EdgeMap.Find(Key);
215		if (!Found) return false;
216	
217		// 销毁 Actor
218		if (*Found)
219		{
220			(*Found)->Destroy();
221		}
222	
223		EdgeMap.Remove(Key);
224	
225		// 更新邻接表
226		if (TSet<int32>* FromNeighbors = AdjacencyList.Find(FromID))
227		{
228			FromNeighbors->Remove(ToID);
229		}
230		if (TSet<int32>* ToNeighbors = AdjacencyList.Find(ToID))
231		{
232			ToNeighbors->Remove(FromID);
233		}
234	
235		// 更新节点-边索引
236		if (TArray<FIntPoint>* FromEdges = NodeEdgeIndex.Find(FromID))
237		{
238			FromEdges->Remove(Key);
239		}
240		if (TArray<FIntPoint>* ToEdges = NodeEdgeIndex.Find(ToID))
241		{
242			ToEdges->Remove(Key);
243		}
244	
245		return true;
