344	bool ALFPWorldMapManager::SaveNodesToCSV(const FString& FilePath)
345	{
346		// CSV 头部（UE DataTable 格式）
347		FString CSVContent = TEXT("---,NodeID,PosX,PosY,NodeType,BattleMapName,StarRating,bCanEscape,BaseGoldReward,BaseFoodReward,EventID,TownBuildingList,ShopID,PrerequisiteNodeIDs\n");
348	
349		for (const auto& Pair : NodeMap)
350		{
351			ALFPWorldMapNode* Node = Pair.Value;
352			if (!Node) continue;
353	
354			FLFPWorldNodeRow Row = Node->ExportToRowData();
355			FString RowName = FString::FromInt(Row.NodeID);
356	
357			// 节点类型枚举名
358			FString NodeTypeStr = UEnum::GetValueAsString(Row.NodeType);
359			NodeTypeStr = NodeTypeStr.RightChop(NodeTypeStr.Find(TEXT("::")) + 2);
360	
361			CSVContent += FString::Printf(TEXT("%s,%d,%f,%f,%s,%s,%d,%s,%d,%d,%s,%s,%s,%s\n"),
362				*RowName,
363				Row.NodeID,
364				Row.PosX,
365				Row.PosY,
366				*NodeTypeStr,
367				*Row.BattleMapName,
368				Row.StarRating,
369				Row.bCanEscape ? TEXT("True") : TEXT("False"),
370				Row.BaseGoldReward,
371				Row.BaseFoodReward,
372				*Row.EventID,
373				*Row.TownBuildingList,
374				*Row.ShopID.ToString(),
375				*Row.PrerequisiteNodeIDs);
376		}
377	
378		// 确保目录存在
379		FString Directory = FPaths::GetPath(FilePath);
380		if (!FPaths::DirectoryExists(Directory))
381		{
382			IFileManager::Get().MakeDirectory(*Directory, true);
383		}
384	
385		bool bSuccess = FFileHelper::SaveStringToFile(CSVContent, *FilePath,
386			FFileHelper::EEncodingOptions::ForceUTF8WithoutBOM);
387	
388		if (bSuccess)
389		{
390			UE_LOG(LogTemp, Log, TEXT("SaveNodesToCSV: 保存 %d 个节点到 %s"), NodeMap.Num(), *FilePath);
391		}
392		else
393		{
394			UE_LOG(LogTemp, Error, TEXT("SaveNodesToCSV: 保存失败 %s"), *FilePath);
395		}
396		return bSuccess;
397	}
