435	bool ALFPWorldMapManager::LoadNodesFromCSV(const FString& FilePath)
436	{
437		FString CSVContent;
438		if (!FFileHelper::LoadFileToString(CSVContent, *FilePath))
439		{
440			UE_LOG(LogTemp, Error, TEXT("LoadNodesFromCSV: 无法加载文件 %s"), *FilePath);
441			return false;
442		}
443	
444		// 使用临时 DataTable 解析 CSV
445		UDataTable* TempTable = NewObject<UDataTable>(GetTransientPackage());
446		TempTable->RowStruct = FLFPWorldNodeRow::StaticStruct();
447	
448		TArray<FString> Problems = TempTable->CreateTableFromCSVString(CSVContent);
449		if (Problems.Num() > 0)
450		{
451			for (const FString& Problem : Problems)
452			{
453				UE_LOG(LogTemp, Warning, TEXT("节点 CSV 解析问题: %s"), *Problem);
454			}
455		}
456	
457		TArray<FLFPWorldNodeRow*> AllRows;
458		TempTable->GetAllRows<FLFPWorldNodeRow>(TEXT("LoadNodes"), AllRows);
459	
460		for (const FLFPWorldNodeRow* Row : AllRows)
461		{
462			if (!Row) continue;
463	
464			ALFPWorldMapNode* Node = SpawnNode(Row->NodeID, FVector2D(Row->PosX, Row->PosY), Row->NodeType);
465			if (Node)
466			{
467				Node->InitFromRowData(*Row);
468			}
469		}
470	
471		UE_LOG(LogTemp, Log, TEXT("LoadNodesFromCSV: 加载了 %d 个节点"), AllRows.Num());
472		return true;
473	}
