548	// ============== 迷雾系统 ==============
549	
550	TSet<int32> ALFPWorldMapManager::GetNodesWithinGraphDistance(int32 StartNodeID, int32 MaxDistance) const
551	{
552		TSet<int32> Result;
553	
554		if (!AdjacencyList.Contains(StartNodeID)) return Result;
555	
556		// BFS
557		TQueue<TPair<int32, int32>> Queue; // <NodeID, Distance>
558		TSet<int32> Visited;
559	
560		Queue.Enqueue(TPair<int32, int32>(StartNodeID, 0));
561		Visited.Add(StartNodeID);
562	
563		while (!Queue.IsEmpty())
564		{
565			TPair<int32, int32> Current;
566			Queue.Dequeue(Current);
567	
568			int32 CurrentID = Current.Key;
569			int32 CurrentDist = Current.Value;
570	
571			Result.Add(CurrentID);
572	
573			if (CurrentDist >= MaxDistance) continue;
574	
575			if (const TSet<int32>* Neighbors = AdjacencyList.Find(CurrentID))
576			{
577				for (int32 NeighborID : *Neighbors)
578				{
579					if (!Visited.Contains(NeighborID))
580					{
581						Visited.Add(NeighborID);
582						Queue.Enqueue(TPair<int32, int32>(NeighborID, CurrentDist + 1));
583					}
584				}
585			}
586		}
587	
588		return Result;
589	}
