662	bool ALFPWorldMapManager::MovePlayer(int32 TargetNodeID)
663	{
664		if (!PlayerState) return false;
665	
666		// 棋子移动中不允许再次移动
667		if (PlayerPawn && PlayerPawn->IsMoving()) return false;
668	
669		bool bMoved = PlayerState->MoveToNode(TargetNodeID, this);
670	
671		if (bMoved)
672		{
673			ALFPWorldMapNode* TargetNode = GetNode(TargetNodeID);
674			if (!TargetNode) return true;
675	
676			// 如果有棋子，启动移动动画，延迟迷雾更新和事件触发
677			if (PlayerPawn)
678			{
679				PendingMoveTargetNodeID = TargetNodeID;
680				FVector TargetLocation = TargetNode->GetActorLocation() + FVector(0, 0, 1);
681				PlayerPawn->MoveToLocation(TargetLocation);
682			}
683			else
684			{
685				// 没有棋子，直接执行后续逻辑
686				HandlePostMove(TargetNodeID);
687			}
688		}
689	
690		return bMoved;
691	}
692	
693	void ALFPWorldMapManager::OnPawnMoveComplete()
694	{
695		if (PendingMoveTargetNodeID >= 0)
696		{
697			int32 NodeID = PendingMoveTargetNodeID;
698			PendingMoveTargetNodeID = -1;
699			HandlePostMove(NodeID);
700		}
701	}
702	
703	void ALFPWorldMapManager::HandlePostMove(int32 TargetNodeID)
704	{
705		// 更新迷雾
706		UpdateFog();
707	
708		// 触发节点事件（首次进入未触发的节点）
709		ALFPWorldMapNode* TargetNode = GetNode(TargetNodeID);
710		if (TargetNode && !TargetNode->bHasBeenTriggered)
711		{
712			switch (TargetNode->NodeType)
713			{
714			case ELFPWorldNodeType::WNT_Battle:
715			case ELFPWorldNodeType::WNT_Event:
716			case ELFPWorldNodeType::WNT_Boss:
717				TargetNode->bHasBeenTriggered = true;
718				TargetNode->UpdateVisualState();
719				break;
720			default:
721				break;
722			}
723		}
724	
725		// 回合压力检查
726		if (PlayerState && PlayerState->IsPastPressureThreshold())
727		{
728			UE_LOG(LogTemp, Warning, TEXT("回合压力: 已超过 %d 回合阈值！当前 %d 回合"),
729				PlayerState->TurnPressureThreshold, PlayerState->CurrentTurn);
730		}
731	}
