154	bool ULFPGameInstance::TryAddOwnedRelic(FName RelicID)
155	{
156		if (RelicID == NAME_None)
157		{
158			UE_LOG(LogTemp, Warning, TEXT("TryAddOwnedRelic: RelicID 无效"));
159			return false;
160		}
161	
162		FLFPRelicDefinition RelicDefinition;
