164		{
165			UE_LOG(LogTemp, Warning, TEXT("TryAddOwnedRelic: 未找到遗物 %s"), *RelicID.ToString());
166			return false;
167		}
168	
169		if (HasRelic(RelicID))
170		{
171			UE_LOG(LogTemp, Warning, TEXT("TryAddOwnedRelic: 已拥有遗物 %s"), *RelicID.ToString());
172			return false;
173		}
174	
175		OwnedRelicIDs.Add(RelicID);
176		UE_LOG(LogTemp, Log, TEXT("获得遗物成功: %s"), *RelicID.ToString());
