196	{
197		if (RelicID == NAME_None)
198		{
199			UE_LOG(LogTemp, Warning, TEXT("TryPurchaseRelic: RelicID 无效"));
200			return false;
201		}
202	
203		if (!SpendGold(Price))
204		{
205			return false;
206		}
207	
208		if (!TryAddOwnedRelic(RelicID))
209		{
210			AddGold(Price);
211			return false;
