390	bool ULFPGameInstance::MergeUnits(bool bSourceAIsParty, int32 SourceAIndex,
391		bool bSourceBIsParty, int32 SourceBIndex, FName TargetTypeID)
392	{
393		TArray<FLFPUnitEntry>& ArrayA = bSourceAIsParty ? PartyUnits : ReserveUnits;
394		TArray<FLFPUnitEntry>& ArrayB = bSourceBIsParty ? PartyUnits : ReserveUnits;
395	
396		if (!ArrayA.IsValidIndex(SourceAIndex) || !ArrayB.IsValidIndex(SourceBIndex))
397		{
398			UE_LOG(LogTemp, Warning, TEXT("MergeUnits: 无效的槽位索引"));
399			return false;
400		}
401	
402		const FLFPUnitEntry& UnitA = ArrayA[SourceAIndex];
403		const FLFPUnitEntry& UnitB = ArrayB[SourceBIndex];
404	
405		// 验证两个源单位 TypeID 相同
406		if (UnitA.TypeID != UnitB.TypeID)
407		{
408			UE_LOG(LogTemp, Warning, TEXT("MergeUnits: 单位类型不匹配 (%s vs %s)"),
409				*UnitA.TypeID.ToString(), *UnitB.TypeID.ToString());
410			return false;
411		}
