170	void ULFPWorldMapEditorComponent::HandleEdgeConnection(ALFPWorldMapNode* Node)
171	{
172		if (!Node) return;
173	
174		ALFPWorldMapManager* Manager = GetWorldMapManager();
175		if (!Manager) return;
176	
177		if (!EdgeStartNode)
178		{
179			// 第一次点击：记录起点
180			EdgeStartNode = Node;
181			EdgeStartNode->SetHighlighted(true);
182			UE_LOG(LogTemp, Log, TEXT("选择边起点: 节点 %d"), EdgeStartNode->NodeID);
183		}
184		else
185		{
186			// 第二次点击：创建边
187			if (EdgeStartNode != Node)
188			{
189				Manager->AddEdge(EdgeStartNode->NodeID, Node->NodeID, BrushEdgeTurnCost);
190				UE_LOG(LogTemp, Log, TEXT("创建边: %d -> %d (消耗 %d 回合)"),
191					EdgeStartNode->NodeID, Node->NodeID, BrushEdgeTurnCost);
192			}
193	
194			// 清除高亮和状态
195			EdgeStartNode->SetHighlighted(false);
196			EdgeStartNode = nullptr;
197		}
198	}
