200	void ULFPWorldMapEditorComponent::HandleEdgeRemoval(ALFPWorldMapNode* Node)
201	{
202		if (!Node) return;
203	
204		ALFPWorldMapManager* Manager = GetWorldMapManager();
205		if (!Manager) return;
206	
207		if (!EdgeRemovalStartNode)
208		{
209			// 第一次点击：记录起点
210			EdgeRemovalStartNode = Node;
211			EdgeRemovalStartNode->SetHighlighted(true);
212			UE_LOG(LogTemp, Log, TEXT("选择要删除的边起点: 节点 %d"), EdgeRemovalStartNode->NodeID);
213		}
214		else
215		{
216			// 第二次点击：删除边
217			if (EdgeRemovalStartNode != Node)
218			{
219				bool bRemoved = Manager->RemoveEdge(EdgeRemovalStartNode->NodeID, Node->NodeID);
220				if (bRemoved)
221				{
222					UE_LOG(LogTemp, Log, TEXT("删除边: %d <-> %d"), EdgeRemovalStartNode->NodeID, Node->NodeID);
223				}
224				else
225				{
226					UE_LOG(LogTemp, Warning, TEXT("边不存在: %d <-> %d"), EdgeRemovalStartNode->NodeID, Node->NodeID);
227				}
228			}
229	
230			// 清除高亮和状态
231			EdgeRemovalStartNode->SetHighlighted(false);
232			EdgeRemovalStartNode = nullptr;
233		}
