272	void ULFPWorldMapEditorComponent::EnterBattleMapEditor()
273	{
274		if (!SelectedNode)
275		{
276			UE_LOG(LogTemp, Warning, TEXT("EnterBattleMapEditor: 未选中节点"));
277			return;
278		}
279	
280		if (SelectedNode->NodeType != ELFPWorldNodeType::WNT_Battle)
281		{
282			UE_LOG(LogTemp, Warning, TEXT("EnterBattleMapEditor: 选中的不是战斗节点"));
283			return;
284		}
285	
286		if (SelectedNode->BattleMapName.IsEmpty())
287		{
288			UE_LOG(LogTemp, Warning, TEXT("EnterBattleMapEditor: 战斗地图名称为空"));
289			return;
290		}
291	
292		// 获取战斗地图编辑器组件（在同一个 PlayerController 上）
293		ULFPMapEditorComponent* BattleEditor = GetOwner()->FindComponentByClass<ULFPMapEditorComponent>();
294		if (!BattleEditor)
295		{
296			UE_LOG(LogTemp, Error, TEXT("EnterBattleMapEditor: 找不到战斗地图编辑器组件"));
297			return;
298		}
299	
300		// 加载战斗地图
301		bool bLoaded = BattleEditor->LoadMap(SelectedNode->BattleMapName);
302		if (!bLoaded)
303		{
304			UE_LOG(LogTemp, Warning, TEXT("EnterBattleMapEditor: 加载战斗地图失败，创建新地图"));
305			BattleEditor->NewMap(10, 10);
306		}
307	
308		// 激活战斗地图编辑器
309		if (!BattleEditor->IsEditorActive())
310		{
311			BattleEditor->ToggleEditorMode();
312		}
313	
314		bIsEditingBattleMap = true;
315		UE_LOG(LogTemp, Log, TEXT("进入战斗地图编辑: %s"), *SelectedNode->BattleMapName);
316	}
