49		// 建筑类型名 → 枚举
50		inline bool StringToBuildingType(const FString& InStr, ELFPTownBuildingType& OutType)
51		{
52			static const TMap<FString, ELFPTownBuildingType> Map = {
53				{TEXT("Shop"), ELFPTownBuildingType::TBT_Shop},
54				{TEXT("EvolutionTower"), ELFPTownBuildingType::TBT_EvolutionTower},
55				{TEXT("Teleport"), ELFPTownBuildingType::TBT_Teleport},
56				{TEXT("QuestNPC"), ELFPTownBuildingType::TBT_QuestNPC},
57				{TEXT("SkillNode"), ELFPTownBuildingType::TBT_SkillNode},
58			};
59			if (const ELFPTownBuildingType* Found = Map.Find(InStr))
60			{
61				OutType = *Found;
62				return true;
63			}
64			return false;
65		}
66	
67		// 枚举 → 建筑类型名
68		inline FString BuildingTypeToString(ELFPTownBuildingType InType)
69		{
70			static const TMap<ELFPTownBuildingType, FString> Map = {
71				{ELFPTownBuildingType::TBT_Shop, TEXT("Shop")},
72				{ELFPTownBuildingType::TBT_EvolutionTower, TEXT("EvolutionTower")},
73				{ELFPTownBuildingType::TBT_Teleport, TEXT("Teleport")},
74				{ELFPTownBuildingType::TBT_QuestNPC, TEXT("QuestNPC")},
75				{ELFPTownBuildingType::TBT_SkillNode, TEXT("SkillNode")},
76			};
77			if (const FString* Found = Map.Find(InType))
78			{
79				return *Found;
80			}
81			return TEXT("Unknown");
82		}
83	
84		// 分号分隔字符串 → 建筑类型数组（如 "Shop;EvolutionTower;Teleport"）
85		inline TArray<ELFPTownBuildingType> ParseBuildingList(const FString& InStr)
86		{
87			TArray<ELFPTownBuildingType> Result;
88			TArray<FString> Tokens;
89			InStr.ParseIntoArray(Tokens, TEXT(";"), true);
90			for (const FString& Token : Tokens)
91			{
92				FString Trimmed = Token.TrimStartAndEnd();
93				ELFPTownBuildingType Type;
94				if (StringToBuildingType(Trimmed, Type))
95				{
96					Result.Add(Type);
97				}
98			}
99			return Result;
100		}
101	
102		// 建筑类型数组 → 分号分隔字符串
103		inline FString SerializeBuildingList(const TArray<ELFPTownBuildingType>& InList)
104		{
105			TArray<FString> Strings;
106			for (ELFPTownBuildingType Type : InList)
107			{
108				Strings.Add(BuildingTypeToString(Type));
109			}
110			return FString::Join(Strings, TEXT(";"));
111		}
