594		if (!ShopNode || !ShopWidgetClass)
595		{
596			return;
597		}
598	
599		ULFPGameInstance* GI = Cast<ULFPGameInstance>(GetGameInstance());
600		if (!GI || ShopNode->ShopID == NAME_None)
601		{
602			UE_LOG(LogTemp, Warning, TEXT("商店节点 %d: ShopID 无效"), ShopNode->NodeID);
603			if (bReturnToTownOnClose && TownWidget && TownWidget->IsInViewport())
604			{
605				TownWidget->SetVisibility(ESlateVisibility::Visible);
606			}
607			return;
608		}
609	
610		FLFPShopDefinition ShopDefinition;
611		if (!GI->FindShopDefinition(ShopNode->ShopID, ShopDefinition))
612		{
613			UE_LOG(LogTemp, Warning, TEXT("商店配置不存在: %s"), *ShopNode->ShopID.ToString());
614			if (bReturnToTownOnClose && TownWidget && TownWidget->IsInViewport())
615			{
616				TownWidget->SetVisibility(ESlateVisibility::Visible);
617			}
618			return;
619		}
620	
621		bReturnToTownAfterShopClose = bReturnToTownOnClose;
622	
623		if (!ShopWidget)
624		{
625			ShopWidget = CreateWidget<ULFPShopWidget>(this, ShopWidgetClass);
626			if (ShopWidget)
627			{
628				ShopWidget->OnClosed.AddDynamic(this, &ALFPWorldMapPlayerController::OnShopWidgetClosed);
629				ShopWidget->AddToViewport();
630			}
631		}
632		else
633		{
634			ShopWidget->SetVisibility(ESlateVisibility::Visible);
635			ShopWidget->AddToViewport();
636		}
637	
638		if (ShopWidget)
639		{
640			ShopWidget->Setup(GI, ShopNode->ShopID, ShopDefinition);
641		}
642	}
